import yaml
from pathlib import Path

def load_register(path: str) -> list[dict]:
    """Load stakeholder register from YAML."""
    with open(path) as f:
        return yaml.safe_load(f)["stakeholders"]

def quadrant_summary(stakeholders: list[dict]) -> dict[str, list[str]]:
    """Group stakeholders by quadrant."""
    quadrants: dict[str, list[str]] = {
        "manage_closely": [],
        "keep_satisfied": [],
        "keep_informed": [],
        "monitor": [],
    }
    for s in stakeholders:
        quadrants[s["quadrant"]].append(s["name"])
    return quadrants

def stale_contacts(stakeholders: list[dict], days_threshold: int = 14) -> list[dict]:
    """Return stakeholders not contacted within threshold (manage_closely and keep_satisfied)."""
    from datetime import date, timedelta
    cutoff = date.today() - timedelta(days=days_threshold)
    stale = []
    for s in stakeholders:
        if s["quadrant"] not in {"manage_closely", "keep_satisfied"}:
            continue
        last = date.fromisoformat(s["last_contact"])
        if last < cutoff:
            stale.append({"name": s["name"], "quadrant": s["quadrant"], "last_contact": s["last_contact"], "owner": s["owner"]})
    return stale

if __name__ == "__main__":
    stakeholders = load_register("stakeholder-register.yaml")
    summary = quadrant_summary(stakeholders)
    print("=== Stakeholder Quadrant Summary ===")
    for q, names in summary.items():
        print(f"{q}: {', '.join(names) if names else 'none'}")
    stale = stale_contacts(stakeholders, days_threshold=14)
    if stale:
        print("
=== ALERT: Stale Contacts (>14 days) ===")
        for s in stale:
            print(f"  {s['name']} ({s['quadrant']}) - last contact {s['last_contact']} - owner: {s['owner']}")
    else:
        print("
All high-priority stakeholders contacted within threshold.")
